// MediaPanel — native React panel for the media app. Shows a grid of
// indexed media files with thumbnails (video/image) or waveforms
// (audio), filter chips, sort, and a detail drawer.
//
// Loaded by the dashboard via dynamic import — the host's React copy
// is provided through an importmap, so we use bare `react` specifiers
// without bundling our own. All data flows through /api/apps/media/*
// (the platform proxy injects the install token); thumbnail/waveform
// images live in storage and are fetched at
// /api/apps/storage/files/<id>/content via same-origin cookies.

import { useCallback, useEffect, useMemo, useRef, useState } from "react";

// Inlined SDK app-event subscription. Each app ships its own copy
// because panels are bundled standalone and apps install independently.
interface AppEventEnvelope<T = unknown> {
  topic: string;
  app: string;
  project_id: string;
  install_id: number;
  seq: number;
  time: string;
  data: T;
}
function useAppEvents<T = unknown>(
  app: string,
  projectId: string | undefined | null,
  onEvent: (ev: AppEventEnvelope<T>) => void,
) {
  const handlerRef = useRef(onEvent);
  handlerRef.current = onEvent;
  useEffect(() => {
    if (!app || !projectId) return;
    const handler = (ev: AppEventEnvelope<T>) => handlerRef.current(ev);
    // Cross-bundle multiplexer: the dashboard publishes a shared
    // (app, project) channel pool on window.__aptevaAppEvents. Every
    // panel mounted in the same realm reuses one EventSource per
    // (app, project) instead of opening its own. Without this, a few
    // panels mounted in the agent detail page burn the browser's
    // per-origin HTTP/1.1 connection budget and stuck POSTs follow.
    const bridge = (window as unknown as {
      __aptevaAppEvents?: {
        subscribe(
          app: string,
          projectId: string,
          fn: (ev: AppEventEnvelope<T>) => void,
        ): () => void;
      };
    }).__aptevaAppEvents;
    if (bridge) {
      return bridge.subscribe(app, projectId, handler);
    }
    // Fallback: panel running outside the dashboard (or before its
    // hook module loaded). Open an EventSource directly.
    let lastSeq = 0;
    let es: EventSource | null = null;
    let cancelled = false;
    let reconnectTimer: number | null = null;
    const connect = () => {
      if (cancelled) return;
      const url =
        `/api/app-events/${encodeURIComponent(app)}` +
        `?project_id=${encodeURIComponent(projectId)}` +
        (lastSeq > 0 ? `&since=${lastSeq}` : "");
      es = new EventSource(url, { withCredentials: true });
      es.onmessage = (e) => {
        try {
          const ev = JSON.parse(e.data) as AppEventEnvelope<T>;
          if (ev.seq <= lastSeq) return;
          lastSeq = ev.seq;
          handlerRef.current(ev);
        } catch {}
      };
      es.onerror = () => {
        if (es && es.readyState === EventSource.CLOSED) {
          if (reconnectTimer) window.clearTimeout(reconnectTimer);
          reconnectTimer = window.setTimeout(connect, 2000);
        }
      };
    };
    connect();
    return () => {
      cancelled = true;
      if (reconnectTimer) window.clearTimeout(reconnectTimer);
      if (es) es.close();
    };
  }, [app, projectId]);
}


// Host props contract — copy of the dashboard's NativePanelProps.
// Inlined rather than imported so the panel has no cross-repo build
// dependency on the dashboard. If the contract changes, every panel
// updates; the dashboard's resolvePanelComponent caller stays the
// source of truth for what's actually passed in.
interface NativePanelProps {
  appName: string;
  installId: number;
  projectId: string;
  instanceId?: number;
}

interface Derivation {
  id: number;
  file_id: string;
  kind: "thumbnail" | "waveform" | "cover" | "keyframe";
  storage_file_id: string;
  width?: number;
  height?: number;
  // position_ms is the source timestamp for keyframes (storyboard
  // frames every keyframe_interval_seconds — v0.13.0+). 0 for
  // single-frame derivations (thumbnail/waveform/cover).
  position_ms?: number;
  status: "ok" | "failed" | "stale";
}

interface MediaRow {
  file_id: string;
  project_id: string;
  name?: string;
  format_name?: string;
  duration_ms?: number;
  bitrate?: number;
  has_video: boolean;
  has_audio: boolean;
  is_image: boolean;
  width?: number;
  height?: number;
  rotation?: number;
  fps?: number;
  video_codec?: string;
  channels?: number;
  sample_rate?: number;
  audio_codec?: string;
  probe_status: "pending" | "ok" | "failed" | "unsupported" | "skipped_size";
  probe_error?: string;
  raw_probe?: unknown;
  // v0.3 — user/agent-supplied prose. Survives reprobe.
  title?: string;
  description?: string;
  alt_text?: string;
  // v0.4 — transcript status, surfaced via LEFT JOIN so the tile can
  // show an icon without a second roundtrip. "" when no transcript.
  transcript_status?: "" | "pending" | "running" | "ok" | "failed" | "skipped";
  // v0.13.0 — audience rating populated by the describer's LLM call.
  // Empty until the describer runs (or stays empty when no descriptions
  // integration is bound). The panel renders a tile badge + filter
  // chip from this.
  audience_rating?: "unrated" | "general" | "mature" | "adult" | "";
  audience_reasoning?: string;
  derivations?: Derivation[];
}

interface Transcript {
  file_id: string;
  status: "pending" | "running" | "ok" | "failed" | "skipped";
  language?: string;
  text?: string;
  segments?: Array<{ start_ms: number; end_ms: number; text: string; speaker?: string }>;
  provider?: string;
  model?: string;
  duration_ms?: number;
  error?: string;
  source_kind?: "auto" | "manual" | "imported";
}

const API = "/api/apps/media";
const STORAGE = "/api/apps/storage";

type Kind = "all" | "video" | "audio" | "image";
type Sort = "created_at" | "duration_ms" | "updated_at";

function formatDuration(ms?: number): string {
  if (!ms) return "—";
  const s = Math.round(ms / 1000);
  const h = Math.floor(s / 3600);
  const m = Math.floor((s % 3600) / 60);
  const sec = s % 60;
  if (h > 0) return `${h}:${String(m).padStart(2, "0")}:${String(sec).padStart(2, "0")}`;
  return `${m}:${String(sec).padStart(2, "0")}`;
}

function formatBitrate(b?: number): string {
  if (!b) return "";
  if (b < 1_000_000) return `${(b / 1000).toFixed(0)} kbps`;
  return `${(b / 1_000_000).toFixed(1)} Mbps`;
}

export default function MediaPanel({ projectId, installId }: NativePanelProps) {
  const [rows, setRows] = useState<MediaRow[]>([]);
  const [status, setStatus] = useState<Record<string, number>>({});
  const [kind, setKind] = useState<Kind>("all");
  const [sort, setSort] = useState<Sort>("created_at");
  const [selected, setSelected] = useState<MediaRow | null>(null);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(true);
  // Folder navigation. "/" = root (all folders). Recursive toggle
  // makes the current view include sub-folders.
  const [folder, setFolder] = useState("/");
  const [childFolders, setChildFolders] = useState<string[]>([]);
  // Default to recursive=true so the root view shows every media
  // file in the project — matches the pre-folder-feature mental
  // model where opening Media meant "see everything." Users who
  // want strict per-folder navigation toggle it off; descending
  // into a sub-folder keeps the toggle's current value.
  const [recursive, setRecursive] = useState(true);

  const withParams = useCallback(
    (extra: Record<string, string> = {}) => {
      const u = new URLSearchParams({
        project_id: projectId,
        install_id: String(installId),
        ...extra,
      });
      return u.toString();
    },
    [projectId, installId],
  );

  const load = useCallback(async () => {
    setLoading(true);
    setError("");
    try {
      const params: Record<string, string> = {
        order_by: sort,
        limit: "200",
      };
      if (kind === "video") params.has_video = "true";
      if (kind === "audio") {
        params.has_audio = "true";
        // exclude videos that happen to have audio
        params.is_image = "false";
      }
      if (kind === "image") params.is_image = "true";
      // Root non-recursive → only files literally at "/" (matches
      // storage panel's behavior). Root recursive → everything in
      // the project (no folder filter). In a sub-folder → exact
      // match by default, prefix when recursive.
      if (recursive && folder === "/") {
        // all — no filter
      } else {
        params.folder = folder;
        if (recursive) params.recursive = "true";
      }
      const [mediaRes, foldersRes] = await Promise.all([
        fetch(`${API}/media?${withParams(params)}`, { credentials: "same-origin" }),
        fetch(`${API}/folders?${withParams({ parent: folder })}`, { credentials: "same-origin" }),
      ]);
      if (!mediaRes.ok) throw new Error(`${mediaRes.status}: ${await mediaRes.text().catch(() => "")}`);
      const data = (await mediaRes.json()) as { media: MediaRow[] };
      setRows(data.media || []);
      if (foldersRes.ok) {
        const fdata = (await foldersRes.json()) as { folders?: string[] };
        setChildFolders(fdata.folders || []);
      } else {
        setChildFolders([]);
      }
    } catch (e) {
      setError((e as Error).message);
    } finally {
      setLoading(false);
    }
  }, [withParams, kind, sort, folder, recursive]);

  // Status counts via the MCP-style summary endpoint — implemented as
  // a fan over rows here to avoid a second roundtrip; once we add a
  // dedicated /status route we'll switch to that.
  useEffect(() => {
    const counts: Record<string, number> = {};
    for (const r of rows) counts[r.probe_status] = (counts[r.probe_status] || 0) + 1;
    setStatus(counts);
  }, [rows]);

  useEffect(() => { load(); }, [load]);

  // Poll while anything is mid-probe so the panel updates live.
  useEffect(() => {
    if (!rows.some((r) => r.probe_status === "pending")) return;
    const id = setInterval(load, 4000);
    return () => clearInterval(id);
  }, [rows, load]);

  // Live refresh — single SSE subscription handling every event we
  // care about. Two separate useAppEvents calls used to open two
  // EventSource connections per mount, and the constant
  // mount/unmount churn would burn through the browser's
  // 6-per-origin HTTP/1.1 connection cap (esp. with the file detail
  // pane also subscribed). Image + Range-fetch requests then sat
  // queued behind pending SSE handshakes, looking like "the panel
  // hangs." Folding into one handler halves the per-mount cost and
  // keeps slots free for the actual content fetches.
  useAppEvents("media", projectId, (ev) => {
    switch (ev.topic) {
      case "media.indexed":
      case "media.transcribed":
        load();
        return;
    }
  });

  const counts = useMemo(() => {
    const c = { all: rows.length, video: 0, audio: 0, image: 0 };
    for (const r of rows) {
      if (r.is_image) c.image++;
      else if (r.has_video) c.video++;
      else if (r.has_audio) c.audio++;
    }
    return c;
  }, [rows]);

  const handleReindex = async (fileId: string) => {
    await fetch(`${API}/media/${fileId}/reindex?${withParams()}`, {
      method: "POST",
      credentials: "same-origin",
    });
    setTimeout(load, 500);
  };

  // queueTranscribe POSTs /media/{id}/transcribe; force=true wipes the
  // existing row first (matches the MCP tool's force semantics). The
  // transcriber goroutine in the sidecar drains the queue async.
  const queueTranscribe = useCallback(
    async (fileId: string, force = false) => {
      const params = withParams(force ? { force: "true" } : {});
      const res = await fetch(`${API}/media/${fileId}/transcribe?${params}`, {
        method: "POST",
        credentials: "same-origin",
      });
      if (!res.ok) {
        throw new Error(`${res.status}: ${await res.text().catch(() => "")}`);
      }
      // Patch in-place so the drawer/tile reflect the new pending status
      // immediately without waiting for the next refresh.
      setRows((prev) =>
        prev.map((r) =>
          r.file_id === fileId ? { ...r, transcript_status: "pending" as const } : r,
        ),
      );
      setSelected((prev) =>
        prev && prev.file_id === fileId
          ? { ...prev, transcript_status: "pending" as const }
          : prev,
      );
    },
    [withParams],
  );

  // (transcript completion was its own useAppEvents; folded into
  // the single subscription above to halve connection count.)

  // saveDescription writes prose via PUT /media/{id}/description (which
  // wraps the same setDescription used by the MCP tool). On success we
  // patch the row in-place so the drawer reflects the save without
  // waiting for a full refresh.
  const saveDescription = useCallback(
    async (fileId: string, fields: { title?: string; description?: string; alt_text?: string }) => {
      const res = await fetch(`${API}/media/${fileId}/description?${withParams()}`, {
        method: "PUT",
        credentials: "same-origin",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(fields),
      });
      if (!res.ok) {
        throw new Error(`${res.status}: ${await res.text().catch(() => "")}`);
      }
      setRows((prev) =>
        prev.map((r) => (r.file_id === fileId ? { ...r, ...fields } : r)),
      );
      setSelected((prev) => (prev && prev.file_id === fileId ? { ...prev, ...fields } : prev));
    },
    [withParams],
  );

  const renderTile = (r: MediaRow) => {
    const thumb = r.derivations?.find((d) => d.kind === "thumbnail" && d.status === "ok");
    const wave = r.derivations?.find((d) => d.kind === "waveform" && d.status === "ok");
    const preview = thumb || wave;
    const previewURL = preview
      ? `${STORAGE}/files/${preview.storage_file_id}/content?${withParams()}`
      : null;
    return (
      <button
        key={r.file_id}
        type="button"
        onClick={() => setSelected(r)}
        className="text-left bg-bg-input/40 border border-border rounded overflow-hidden hover:border-accent/50 transition-colors flex flex-col"
      >
        {/* Square thumbnail wrapper. We use `position: relative` +
            absolutely-positioned children rather than a flex parent
            because `height: 100%` on a flex item whose parent's height
            comes from `aspect-ratio` doesn't resolve in every browser —
            the percentage falls back to `auto` (natural image height)
            and the tile grows to the source's full aspect ratio.
            That's why portrait videos were rendering as 1080×1918
            tiles instead of 200×200 cropped squares. Absolute children
            sized via inset:0 are unaffected by the parent's flex
            algorithm. */}
        <div
          style={{ aspectRatio: "1 / 1", position: "relative" }}
          className="bg-bg-input relative overflow-hidden"
        >
          {previewURL ? (
            <img
              src={previewURL}
              alt=""
              style={{
                position: "absolute",
                inset: 0,
                width: "100%",
                height: "100%",
                objectFit: "cover",
              }}
            />
          ) : (
            <div className="absolute inset-0 flex items-center justify-center text-text-dim">
              <KindIcon row={r} className="w-8 h-8" />
            </div>
          )}
          {r.transcript_status ? (
            <span
              className={`absolute top-1 right-1 ${transcriptBadgeClass(r.transcript_status)}`}
              title={`Transcript: ${r.transcript_status}`}
            >
              <TranscriptStatusIcon status={r.transcript_status} className="w-3.5 h-3.5" />
            </span>
          ) : null}
        </div>
        <div className="p-2 flex flex-col gap-0.5">
          <div className="text-xs text-text font-medium truncate" title={r.file_id}>
            {r.title || `#${r.file_id}`}
          </div>
          {r.description ? (
            <div
              style={{ fontSize: 11 }}
              className="text-text-muted line-clamp-2"
              title={r.description}
            >
              {r.description}
            </div>
          ) : null}
          <div style={{ fontSize: 11 }} className="text-text-muted flex flex-wrap gap-1">
            {r.duration_ms ? <span>{formatDuration(r.duration_ms)}</span> : null}
            {r.width && r.height ? <span>· {r.width}×{r.height}</span> : null}
            {r.video_codec ? <span>· {r.video_codec}</span> : null}
            {!r.video_codec && r.audio_codec ? <span>· {r.audio_codec}</span> : null}
          </div>
        </div>
      </button>
    );
  };

  // Breadcrumb segments. "/" = root; "/clips/q3/" yields ["clips","q3"].
  const breadcrumbParts = folder.split("/").filter(Boolean);

  return (
    <div className="h-full flex flex-col p-6 gap-4">
      {/* Folder breadcrumb. Click any segment to jump to that level. */}
      <nav className="flex items-center gap-1 text-sm flex-wrap">
        <button
          type="button"
          onClick={() => setFolder("/")}
          className="text-accent hover:underline"
        >/</button>
        {breadcrumbParts.map((part, i) => {
          const target = "/" + breadcrumbParts.slice(0, i + 1).join("/") + "/";
          const last = i === breadcrumbParts.length - 1;
          return (
            <span key={target} className="flex items-center gap-1">
              <span className="text-text-dim">/</span>
              {last ? (
                <span className="text-text">{part}</span>
              ) : (
                <button
                  type="button"
                  className="text-accent hover:underline"
                  onClick={() => setFolder(target)}
                >{part}</button>
              )}
            </span>
          );
        })}
        <span className="ml-3 text-text-dim text-xs">·</span>
        <label className="text-xs text-text-dim flex items-center gap-1 cursor-pointer">
          <input
            type="checkbox"
            checked={recursive}
            onChange={(e) => setRecursive(e.target.checked)}
            className="accent-accent"
          />
          recursive
        </label>
      </nav>

      {/* Render queue widget — shows pending / running / recent jobs.
          Live-updates via render.* SSE events; the initial snapshot
          comes from GET /renders/summary. Collapsed by default
          (header-only) so it doesn't crowd the catalog view when
          there's nothing interesting to look at. */}
      <RenderQueue projectId={projectId} installId={installId} />

      <div className="flex items-center gap-2 flex-wrap">
        {(["all", "video", "audio", "image"] as Kind[]).map((k) => (
          <button
            key={k}
            type="button"
            onClick={() => setKind(k)}
            className={`px-2 py-1 text-xs rounded border transition-colors ${
              kind === k
                ? "bg-accent text-bg border-accent"
                : "border-border text-text-muted hover:text-text hover:border-accent/40"
            }`}
          >
            {k} {counts[k] ? <span className="opacity-60">({counts[k]})</span> : null}
          </button>
        ))}
        <span className="text-text-dim text-xs ml-2">·</span>
        <label className="text-xs text-text-dim">sort</label>
        <select
          value={sort}
          onChange={(e) => setSort(e.target.value as Sort)}
          className="bg-bg-input border border-border rounded px-2 py-1 text-xs"
        >
          <option value="created_at">newest</option>
          <option value="duration_ms">longest</option>
          <option value="updated_at">recently updated</option>
        </select>
        <div className="flex-1" />
        <button
          type="button"
          onClick={load}
          className="px-2 py-1 text-xs border border-border rounded hover:bg-bg-input"
        >
          Refresh
        </button>
      </div>

      <div className="flex-1 overflow-auto">
        {error ? (
          <div className="text-red text-sm p-4">{error}</div>
        ) : loading && rows.length === 0 && childFolders.length === 0 ? (
          <div className="text-text-muted text-sm text-center mt-12">Loading…</div>
        ) : rows.length === 0 && childFolders.length === 0 ? (
          <div className="text-text-muted text-sm text-center mt-12">
            {folder === "/"
              ? "No indexed media yet. Upload audio, video, or image files to storage — the indexer picks them up within ~30s."
              : `No media in ${folder}.`}
          </div>
        ) : (
          <>
            {childFolders.length > 0 && (
              <div className="mb-3 flex flex-wrap gap-2">
                {childFolders.map((name) => (
                  <button
                    key={name}
                    type="button"
                    onClick={() => setFolder(folder + name + "/")}
                    className="flex items-center gap-1 px-3 py-2 text-xs border border-border rounded hover:bg-bg-input hover:border-accent/40"
                  >
                    <span aria-hidden>📁</span>
                    <span className="text-text">{name}</span>
                  </button>
                ))}
              </div>
            )}
            <div
              style={{
                display: "grid",
                gridTemplateColumns: "repeat(auto-fill, minmax(200px, 1fr))",
                gap: "0.75rem",
              }}
            >
              {rows.map(renderTile)}
            </div>
          </>
        )}
      </div>

      <footer className="text-xs text-text-dim flex items-center gap-3 border-t border-border pt-2">
        <span>{rows.length} indexed</span>
        {(["pending", "failed", "unsupported", "skipped_size"] as const).map((s) =>
          status[s] ? (
            <span
              key={s}
              className={
                s === "pending"
                  ? "text-accent"
                  : s === "failed"
                    ? "text-red"
                    : "text-text-muted"
              }
            >
              · {status[s]} {s.replace("_", " ")}
            </span>
          ) : null,
        )}
      </footer>

      {selected && (
        <DetailDrawer
          row={selected}
          onClose={() => setSelected(null)}
          onReindex={() => handleReindex(selected.file_id)}
          onSaveDescription={(fields) => saveDescription(selected.file_id, fields)}
          onTranscribe={(force) => queueTranscribe(selected.file_id, force)}
          previewBase={`${STORAGE}/files`}
          apiBase={API}
          query={withParams()}
        />
      )}
    </div>
  );
}

function DetailDrawer({
  row,
  onClose,
  onReindex,
  onSaveDescription,
  onTranscribe,
  previewBase,
  apiBase,
  query,
}: {
  row: MediaRow;
  onClose: () => void;
  onReindex: () => void;
  onSaveDescription: (fields: { title?: string; description?: string; alt_text?: string }) => Promise<void>;
  onTranscribe: (force: boolean) => Promise<void>;
  previewBase: string;
  apiBase: string;
  query: string;
}) {
  const thumb = row.derivations?.find((d) => d.kind === "thumbnail");
  const wave = row.derivations?.find((d) => d.kind === "waveform");
  return (
    <div className="fixed inset-0 z-30 flex" onClick={onClose}>
      <div className="flex-1 bg-black/50" />
      <aside
        onClick={(e) => e.stopPropagation()}
        style={{ width: 480, maxWidth: "100%" }}
        className="bg-bg border-l border-border h-full overflow-auto"
      >
        <div className="p-4 border-b border-border flex items-center justify-between">
          <div>
            <div className="text-xs text-text-dim">file_id</div>
            <div className="text-text font-medium">#{row.file_id}</div>
          </div>
          <button
            type="button"
            onClick={onClose}
            className="text-text-dim hover:text-text text-sm px-2 py-1"
          >
            ✕
          </button>
        </div>
        <div className="p-4 space-y-4">
          {row.is_image ? (
            // Image first — ffprobe reports images as a single-frame
            // video stream (has_video=true), so the video branch
            // would mis-render an image as a player. is_image is set
            // by the prober when codec_type is image-shaped; trust
            // it over has_video for the rendering decision.
            //
            // Click to open full-resolution in a new tab; the inline
            // preview keeps the drawer compact.
            <a
              href={`${previewBase}/${row.file_id}/content?${query}`}
              target="_blank"
              rel="noopener"
              title="Open full image"
            >
              <img
                src={`${previewBase}/${row.file_id}/content?${query}`}
                alt={row.alt_text || row.title || ""}
                className="w-full rounded border border-border"
              />
            </a>
          ) : row.has_video ? (
            // Native player against the source. preload="metadata"
            // means the browser fetches just the moov atom + first
            // keyframe for the poster — opening the drawer is fast
            // even on a multi-GB clip; clicking play streams the rest.
            <video
              src={`${previewBase}/${row.file_id}/content?${query}`}
              poster={
                thumb
                  ? `${previewBase}/${thumb.storage_file_id}/content?${query}`
                  : undefined
              }
              controls
              preload="metadata"
              playsInline
              className="w-full rounded border border-border bg-black"
            />
          ) : row.has_audio ? (
            <>
              {wave && (
                <img
                  src={`${previewBase}/${wave.storage_file_id}/content?${query}`}
                  alt="waveform"
                  className="w-full rounded border border-border"
                />
              )}
              <audio
                src={`${previewBase}/${row.file_id}/content?${query}`}
                controls
                preload="metadata"
                className="w-full"
              />
            </>
          ) : (thumb || wave) ? (
            <img
              src={`${previewBase}/${(thumb || wave)!.storage_file_id}/content?${query}`}
              alt=""
              className="w-full rounded border border-border"
            />
          ) : null}
          <a
            href={`${previewBase}/${row.file_id}/content?${query}`}
            target="_blank"
            rel="noopener"
            className="block text-xs text-accent hover:underline truncate"
          >
            Open source file ↗
          </a>
          <DescriptionEditor row={row} onSave={onSaveDescription} />
          <AudienceRatingSection row={row} apiBase={apiBase} query={query} />
          <KeyframesStrip row={row} previewBase={previewBase} query={query} />
          <OperationsSection
            row={row}
            apiBase={apiBase}
            previewBase={previewBase}
            query={query}
          />
          {row.has_audio ? (
            <TranscriptSection
              row={row}
              apiBase={apiBase}
              query={query}
              onTranscribe={onTranscribe}
            />
          ) : null}
          <Section title="Container">
            <Field label="format" value={row.format_name} />
            <Field label="duration" value={formatDuration(row.duration_ms)} />
            <Field label="bitrate" value={formatBitrate(row.bitrate)} />
          </Section>
          {row.has_video && (
            <Section title="Video">
              <Field label="codec" value={row.video_codec} />
              <Field
                label="size"
                value={row.width && row.height ? `${row.width}×${row.height}` : undefined}
              />
              <Field label="fps" value={row.fps ? row.fps.toFixed(2) : undefined} />
            </Section>
          )}
          {row.has_audio && (
            <Section title="Audio">
              <Field label="codec" value={row.audio_codec} />
              <Field label="channels" value={row.channels?.toString()} />
              <Field
                label="sample rate"
                value={row.sample_rate ? `${(row.sample_rate / 1000).toFixed(1)} kHz` : undefined}
              />
            </Section>
          )}
          <Section title="Status">
            <Field label="probe" value={row.probe_status} />
            {row.probe_error ? <Field label="error" value={row.probe_error} /> : null}
          </Section>
          <details>
            <summary className="text-xs text-text-dim cursor-pointer hover:text-text">
              raw ffprobe
            </summary>
            <pre style={{ fontSize: 11 }} className="bg-bg-input border border-border rounded p-2 mt-2 overflow-auto max-h-96">
              {JSON.stringify(row.raw_probe, null, 2)}
            </pre>
          </details>
          <button
            type="button"
            onClick={onReindex}
            className="px-3 py-1 text-sm border border-accent text-accent rounded hover:bg-accent hover:text-bg"
          >
            Re-index
          </button>
        </div>
      </aside>
    </div>
  );
}

// ─── Operations (renders: trim / resize / transcode / …) ─────────
//
// Per-file render operations exposed as a button row at the top of
// the drawer. Each operation opens a modal with the minimum fields it
// needs; submit POSTs to /renders and gets back a render_id. The
// submitted renders are tracked locally + polled every 2s until
// terminal; when they finish ok the output file_id is rendered as a
// "Open output" link to the storage content endpoint.
//
// Defaults are pulled from the row's metadata when sensible (trim
// end_ms defaults to the source duration; extract_frame defaults to
// the middle; resize keeps aspect when only width is provided).
// Operation availability is gated on the file's media kind — a
// silent video doesn't get "extract audio", an image doesn't get
// "trim", etc.
//
// Output naming is left to the backend (it builds a sane
// "<original>-<op>.<ext>" when output_name is empty), so the modal
// stays compact. Operators wanting a specific name can rename after
// the fact via storage.

type OpName = "trim" | "resize" | "transcode" | "crop" | "extract_frame" | "audio_extract" | "extract_reel";

interface OpDef {
  name: OpName;
  label: string;
  needs: (row: MediaRow) => boolean;
}

const ALL_OPS: OpDef[] = [
  { name: "trim",          label: "Trim",           needs: (r) => (r.has_video || r.has_audio) && !r.is_image },
  { name: "resize",        label: "Resize",         needs: (r) => r.has_video || r.is_image },
  { name: "transcode",     label: "Transcode",      needs: (r) => (r.has_video || r.has_audio) && !r.is_image },
  { name: "crop",          label: "Crop",           needs: (r) => r.has_video || r.is_image },
  { name: "extract_frame", label: "Extract frame",  needs: (r) => r.has_video && !r.is_image },
  { name: "audio_extract", label: "Audio only",     needs: (r) => r.has_video && r.has_audio },
  { name: "extract_reel",  label: "9:16 reel",      needs: (r) => r.has_video && !r.is_image },
];

function OperationsSection({
  row, apiBase, previewBase, query,
}: {
  row: MediaRow;
  apiBase: string;
  previewBase: string;
  query: string;
}) {
  const [openOp, setOpenOp] = useState<OpName | null>(null);
  const [activeRenders, setActiveRenders] = useState<number[]>([]);
  const [submitError, setSubmitError] = useState<string>("");

  const ops = ALL_OPS.filter((o) => o.needs(row));
  if (ops.length === 0) return null;

  // Don't use the shared <Section> wrapper here — it forces a 2-col
  // grid (100px | 1fr) designed for label/value rows, which would
  // squeeze the button strip into the first 100px column. Render
  // the section directly with a flex layout so buttons flow
  // horizontally and wrap naturally.
  return (
    <section>
      <h3 className="text-xs uppercase tracking-wide text-text-dim mb-1">Operations</h3>
      <div className="flex flex-wrap gap-1.5">
        {ops.map((op) => (
          <button
            key={op.name}
            type="button"
            onClick={() => { setOpenOp(op.name); setSubmitError(""); }}
            className="px-2 py-1 text-xs border border-border rounded text-text hover:bg-bg-input hover:border-accent whitespace-nowrap"
          >
            {op.label}
          </button>
        ))}
      </div>
      {submitError && (
        <div className="text-error text-xs mt-2">{submitError}</div>
      )}
      {openOp && (
        <OperationModal
          op={openOp}
          row={row}
          apiBase={apiBase}
          onClose={() => setOpenOp(null)}
          onSubmitted={(id) => {
            setOpenOp(null);
            setActiveRenders((cur) => [id, ...cur]);
          }}
          onError={(msg) => setSubmitError(msg)}
        />
      )}
      {activeRenders.length > 0 && (
        <div className="space-y-2 mt-3">
          {activeRenders.map((id) => (
            <RenderStatusCard
              key={id}
              renderId={id}
              apiBase={apiBase}
              previewBase={previewBase}
              query={query}
            />
          ))}
        </div>
      )}
    </section>
  );
}

interface RenderRow {
  id: number;
  operation: string;
  status: "pending" | "running" | "ok" | "failed" | "cancelled";
  progress_pct?: number;
  output_file_id?: number;
  error?: string;
  started_at?: string;
  finished_at?: string;
}

// RenderStatusCard polls the backend every 2s for one render's state
// and renders a compact status pill + (when terminal) an action.
// Stops polling on terminal states. No cleanup needed beyond the
// interval clear in the effect's return value.
function RenderStatusCard({
  renderId, apiBase, previewBase, query,
}: {
  renderId: number;
  apiBase: string;
  previewBase: string;
  query: string;
}) {
  const [row, setRow] = useState<RenderRow | null>(null);
  const [err, setErr] = useState<string>("");
  // Wall-clock seconds since the card was mounted. Drives the
  // "running for Ns" line so operators know *something* is
  // progressing even when the server-side progress_pct hasn't
  // ticked off 0 yet (remote renders only push 0→50 on the first
  // `out_time_ms=` sighting from ffmpeg's progress pipe, polled
  // every 5s — renders that finish under 5s never get a numeric
  // progress signal at all).
  const cardMountedAt = useMemo(() => Date.now(), []);
  const [nowMs, setNowMs] = useState(Date.now());

  useEffect(() => {
    let mounted = true;
    let interval: ReturnType<typeof setInterval> | null = null;
    let clock: ReturnType<typeof setInterval> | null = null;
    const poll = async () => {
      try {
        const r = await fetch(`${apiBase}/renders/${renderId}?${query}`, { credentials: "same-origin" });
        if (!r.ok) throw new Error(`HTTP ${r.status}`);
        const data = (await r.json()) as RenderRow;
        if (!mounted) return;
        setRow(data);
        if (data.status === "ok" || data.status === "failed" || data.status === "cancelled") {
          if (interval) { clearInterval(interval); interval = null; }
          if (clock) { clearInterval(clock); clock = null; }
        }
      } catch (e) {
        if (mounted) setErr(e instanceof Error ? e.message : String(e));
      }
    };
    poll();
    interval = setInterval(poll, 2000);
    // Tick the clock every second so the elapsed-time display
    // updates even when the 2s poll hasn't fired yet.
    clock = setInterval(() => mounted && setNowMs(Date.now()), 1000);
    return () => {
      mounted = false;
      if (interval) clearInterval(interval);
      if (clock) clearInterval(clock);
    };
  }, [renderId, apiBase, query]);

  if (err && !row) {
    return (
      <div className="text-xs text-error border border-error/40 rounded p-2">
        render #{renderId}: {err}
      </div>
    );
  }
  if (!row) {
    return <div className="text-xs text-text-dim">render #{renderId}: loading…</div>;
  }

  const badgeClass =
    row.status === "ok"        ? "bg-green/20 text-green border-green/40"
    : row.status === "failed"  ? "bg-red/20 text-red border-red/40"
    : row.status === "cancelled" ? "bg-text-dim/20 text-text-dim border-border"
    : "bg-yellow/20 text-yellow border-yellow/40"; // pending | running

  const elapsedS = Math.max(0, Math.floor((nowMs - cardMountedAt) / 1000));
  const running = row.status === "pending" || row.status === "running";
  const pct = Math.max(0, Math.min(100, row.progress_pct ?? 0));

  return (
    <div className="border border-border rounded p-2 text-xs space-y-1.5">
      <div className="flex items-center justify-between gap-2">
        <div className="text-text-dim">
          <span className="font-mono">#{row.id}</span>{" "}
          <span className="text-text">{row.operation}</span>
        </div>
        <span className={`px-1.5 py-0.5 rounded border text-[10px] uppercase ${badgeClass}`}>
          {row.status}
        </span>
      </div>
      {running && (
        <>
          {/* Thicker bar with explicit % text. Pulses gently when
              progress_pct hasn't ticked off 0 yet so operators can
              see the panel is alive even before ffmpeg surfaces
              its first progress event. */}
          <div className="w-full bg-bg-input rounded h-2 overflow-hidden relative">
            <div
              className={`h-full bg-yellow transition-all ${pct === 0 ? "animate-pulse" : ""}`}
              style={{ width: `${pct === 0 ? 100 : pct}%`, opacity: pct === 0 ? 0.3 : 1 }}
            />
          </div>
          <div className="flex justify-between text-text-dim text-[10px]">
            <span>{pct > 0 ? `${pct}%` : "Working…"}</span>
            <span>{elapsedS}s elapsed</span>
          </div>
        </>
      )}
      {row.status === "ok" && row.output_file_id ? (
        <div className="space-y-1">
          <a
            href={`${previewBase}/${row.output_file_id}/content?${query}`}
            target="_blank"
            rel="noopener"
            className="text-accent hover:underline block"
          >
            Open output (file_id #{row.output_file_id}) ↗
          </a>
          <div className="text-text-dim text-[10px]">Done in {elapsedS}s.</div>
        </div>
      ) : null}
      {row.status === "failed" && row.error ? (
        <div className="text-error break-words">{row.error}</div>
      ) : null}
    </div>
  );
}

// OperationModal — per-op form. Each op has a focused set of fields;
// missing optional fields fall back to backend defaults (output_name
// builds "<src>-<op>.<ext>" automatically; trim end_ms defaults to
// source duration). Submit POSTs to /renders and bubbles the
// render_id up so the section can start polling.
function OperationModal({
  op, row, apiBase, onClose, onSubmitted, onError,
}: {
  op: OpName;
  row: MediaRow;
  apiBase: string;
  onClose: () => void;
  onSubmitted: (id: number) => void;
  onError: (msg: string) => void;
}) {
  // One state object keyed by field name — cheaper than threading a
  // separate useState per per-op field.
  const [fields, setFields] = useState<Record<string, string>>(() => defaultFields(op, row));
  const [busy, setBusy] = useState(false);

  const set = (k: string, v: string) => setFields((f) => ({ ...f, [k]: v }));

  const submit = async (e: React.FormEvent) => {
    e.preventDefault();
    setBusy(true);
    try {
      const params = buildParams(op, fields);
      const r = await fetch(`${apiBase}/renders?project_id=${encodeURIComponent(row.project_id)}`, {
        method: "POST",
        credentials: "same-origin",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          operation: op,
          file_id: row.file_id,
          params,
        }),
      });
      if (!r.ok) throw new Error(await r.text().catch(() => `HTTP ${r.status}`));
      const data = (await r.json()) as { render_id: number };
      onSubmitted(data.render_id);
    } catch (e) {
      onError("Render submit failed: " + (e instanceof Error ? e.message : String(e)));
    } finally {
      setBusy(false);
    }
  };

  const title = ALL_OPS.find((o) => o.name === op)?.label ?? op;

  return (
    <div className="fixed inset-0 z-40 flex items-center justify-center bg-black/50" onClick={onClose}>
      <form
        onClick={(e) => e.stopPropagation()}
        onSubmit={submit}
        className="bg-bg border border-border rounded p-5 space-y-3"
        style={{ width: 360 }}
      >
        <h3 className="text-text font-semibold text-sm">{title}</h3>
        {opFieldDefs(op).map((fd) => (
          <label key={fd.key} className="block">
            <span className="text-xs text-text-muted">{fd.label}</span>
            {fd.type === "select" ? (
              <select
                value={fields[fd.key] || ""}
                onChange={(e) => set(fd.key, e.target.value)}
                className="w-full mt-1 bg-bg-input border border-border rounded px-2 py-1 text-sm font-mono"
              >
                {fd.options!.map((opt) => (
                  <option key={opt} value={opt}>{opt}</option>
                ))}
              </select>
            ) : (
              <input
                type={fd.type === "number" ? "number" : "text"}
                value={fields[fd.key] || ""}
                onChange={(e) => set(fd.key, e.target.value)}
                placeholder={fd.placeholder}
                className="w-full mt-1 bg-bg-input border border-border rounded px-2 py-1 text-sm font-mono"
              />
            )}
            {fd.hint && (
              <span className="text-[10px] text-text-dim block mt-0.5">{fd.hint}</span>
            )}
          </label>
        ))}
        <div className="flex justify-end gap-2 pt-1">
          <button
            type="button"
            onClick={onClose}
            disabled={busy}
            className="px-3 py-1 text-sm border border-border rounded text-text-muted hover:text-text"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={busy}
            className="px-3 py-1 text-sm bg-accent text-bg rounded hover:bg-accent-hover disabled:opacity-50"
          >
            {busy ? "Submitting…" : "Submit"}
          </button>
        </div>
      </form>
    </div>
  );
}

// ─── per-op field definitions ────────────────────────────────────

interface FieldDef {
  key: string;
  label: string;
  type: "number" | "text" | "select";
  placeholder?: string;
  hint?: string;
  options?: string[];
}

function opFieldDefs(op: OpName): FieldDef[] {
  switch (op) {
    case "trim":
      return [
        { key: "start_ms", label: "Start (ms)",  type: "number", placeholder: "0" },
        { key: "end_ms",   label: "End (ms)",    type: "number", placeholder: "30000" },
      ];
    case "resize":
      return [
        { key: "width",        label: "Width (px)",  type: "number", placeholder: "1280" },
        { key: "height",       label: "Height (px)", type: "number", placeholder: "720", hint: "Leave empty if keep_aspect=true" },
        { key: "keep_aspect",  label: "Keep aspect", type: "select", options: ["true", "false"] },
      ];
    case "transcode":
      return [
        { key: "format",       label: "Format",      type: "select", options: ["mp4", "webm", "mkv", "mp3", "wav", "m4a", "opus"] },
        { key: "video_codec",  label: "Video codec", type: "text",   placeholder: "libx264 (optional)" },
        { key: "audio_codec",  label: "Audio codec", type: "text",   placeholder: "aac (optional)" },
        { key: "bitrate",      label: "Bitrate",     type: "text",   placeholder: "1M (optional)" },
      ];
    case "crop":
      return [
        { key: "x",      label: "X (px)",      type: "number", placeholder: "0" },
        { key: "y",      label: "Y (px)",      type: "number", placeholder: "0" },
        { key: "width",  label: "Width (px)",  type: "number", placeholder: "640" },
        { key: "height", label: "Height (px)", type: "number", placeholder: "360" },
      ];
    case "extract_frame":
      return [
        { key: "at_ms", label: "At (ms)",    type: "number", placeholder: "1000" },
        { key: "width", label: "Width (px)", type: "number", placeholder: "1280 (optional)" },
      ];
    case "audio_extract":
      return [
        { key: "format", label: "Format", type: "select", options: ["mp3", "wav", "m4a", "opus"] },
      ];
    case "extract_reel":
      return [
        { key: "start_ms",     label: "Start (ms)",       type: "number", placeholder: "0" },
        { key: "end_ms",       label: "End (ms)",         type: "number", placeholder: "10000" },
        { key: "target_ratio", label: "Aspect ratio",     type: "select", options: ["9:16", "1:1", "4:5", "16:9"] },
        { key: "output_width", label: "Output width (px)",type: "number", placeholder: "1080" },
      ];
  }
}

function defaultFields(op: OpName, row: MediaRow): Record<string, string> {
  const out: Record<string, string> = {};
  switch (op) {
    case "trim":
      out.start_ms = "0";
      if (row.duration_ms) out.end_ms = String(row.duration_ms);
      break;
    case "resize":
      out.keep_aspect = "true";
      if (row.width) out.width = String(row.width);
      break;
    case "transcode":
      out.format = "mp4";
      break;
    case "extract_frame":
      out.at_ms = row.duration_ms ? String(Math.floor(row.duration_ms / 2)) : "1000";
      break;
    case "audio_extract":
      out.format = "mp3";
      break;
    case "extract_reel":
      out.start_ms = "0";
      if (row.duration_ms) out.end_ms = String(Math.min(row.duration_ms, 10000));
      out.target_ratio = "9:16";
      out.output_width = "1080";
      break;
    case "crop":
      out.x = "0";
      out.y = "0";
      if (row.width) out.width = String(Math.floor(row.width / 2));
      if (row.height) out.height = String(Math.floor(row.height / 2));
      break;
  }
  return out;
}

// buildParams converts the form's stringy fields into the typed
// params object the backend expects. Numbers parse to Number,
// "true"/"false" to bool, empty strings drop the field so the
// backend default applies. Output name is intentionally not
// configurable here — the backend builds "<src>-<op>.<ext>".
function buildParams(op: OpName, fields: Record<string, string>): Record<string, unknown> {
  const out: Record<string, unknown> = {};
  for (const fd of opFieldDefs(op)) {
    const v = (fields[fd.key] ?? "").trim();
    if (!v) continue;
    if (fd.type === "number") {
      const n = Number(v);
      if (!Number.isFinite(n)) continue;
      out[fd.key] = n;
    } else if (v === "true" || v === "false") {
      out[fd.key] = v === "true";
    } else {
      out[fd.key] = v;
    }
  }
  return out;
}

function Section({ title, children }: { title: string; children: React.ReactNode }) {
  return (
    <section>
      <h3 className="text-xs uppercase tracking-wide text-text-dim mb-1">{title}</h3>
      <div
        style={{ display: "grid", gridTemplateColumns: "100px 1fr" }}
        className="gap-y-1 text-sm"
      >{children}</div>
    </section>
  );
}

function Field({ label, value }: { label: string; value?: string | number }) {
  if (value === undefined || value === null || value === "") return null;
  return (
    <>
      <span className="text-text-muted">{label}</span>
      <span className="text-text">{String(value)}</span>
    </>
  );
}

// DescriptionEditor — collapsible inline edit of title / description /
// alt_text for one media row. View mode renders the prose read-only;
// edit mode shows three inputs + Save/Cancel. Saves go through the
// parent's onSave callback (which calls PUT /media/{id}/description),
// so the same path the agent uses also writes from the panel.
function DescriptionEditor({
  row,
  onSave,
}: {
  row: MediaRow;
  onSave: (fields: { title?: string; description?: string; alt_text?: string }) => Promise<void>;
}) {
  const [editing, setEditing] = useState(false);
  const [title, setTitle] = useState(row.title || "");
  const [desc, setDesc] = useState(row.description || "");
  const [alt, setAlt] = useState(row.alt_text || "");
  const [saving, setSaving] = useState(false);
  const [err, setErr] = useState("");

  // Reset local state when the selected row changes (the drawer is
  // reused for different files via key={row.file_id} on selection).
  useEffect(() => {
    setTitle(row.title || "");
    setDesc(row.description || "");
    setAlt(row.alt_text || "");
    setEditing(false);
    setErr("");
  }, [row.file_id]);

  const dirty =
    (row.title || "") !== title ||
    (row.description || "") !== desc ||
    (row.alt_text || "") !== alt;

  const handleSave = async () => {
    setSaving(true);
    setErr("");
    try {
      // Send only fields that actually changed — server treats missing
      // keys as "preserve", empty string as "clear", which is exactly
      // what we want.
      const fields: { title?: string; description?: string; alt_text?: string } = {};
      if ((row.title || "") !== title) fields.title = title;
      if ((row.description || "") !== desc) fields.description = desc;
      if ((row.alt_text || "") !== alt) fields.alt_text = alt;
      await onSave(fields);
      setEditing(false);
    } catch (e) {
      setErr((e as Error).message);
    } finally {
      setSaving(false);
    }
  };

  const handleCancel = () => {
    setTitle(row.title || "");
    setDesc(row.description || "");
    setAlt(row.alt_text || "");
    setEditing(false);
    setErr("");
  };

  const empty = !row.title && !row.description && !row.alt_text;

  if (!editing) {
    return (
      <section>
        <div className="flex items-center justify-between mb-1">
          <h3 className="text-xs uppercase tracking-wide text-text-dim">Description</h3>
          <button
            type="button"
            onClick={() => setEditing(true)}
            className="text-xs text-accent hover:underline"
          >
            {empty ? "Add description" : "Edit"}
          </button>
        </div>
        {empty ? (
          <div className="text-xs text-text-dim italic">
            No description set. Add one to give agents and viewers context.
          </div>
        ) : (
          <div className="space-y-1 text-sm">
            {row.title ? <div className="text-text font-medium">{row.title}</div> : null}
            {row.description ? (
              <div className="text-text-muted whitespace-pre-wrap">{row.description}</div>
            ) : null}
            {row.alt_text ? (
              <div className="text-xs text-text-dim">
                <span className="text-text-muted">alt: </span>
                {row.alt_text}
              </div>
            ) : null}
          </div>
        )}
      </section>
    );
  }

  return (
    <section>
      <div className="flex items-center justify-between mb-1">
        <h3 className="text-xs uppercase tracking-wide text-text-dim">Description</h3>
      </div>
      <div className="space-y-2 text-sm">
        <label className="block">
          <span className="text-xs text-text-muted block mb-0.5">Title</span>
          <input
            type="text"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            className="w-full bg-bg-input border border-border rounded px-2 py-1 text-sm"
            placeholder="Short label, e.g. Q3 board sync"
            disabled={saving}
          />
        </label>
        <label className="block">
          <span className="text-xs text-text-muted block mb-0.5">Description</span>
          <textarea
            value={desc}
            onChange={(e) => setDesc(e.target.value)}
            rows={4}
            className="w-full bg-bg-input border border-border rounded px-2 py-1 text-sm font-mono"
            placeholder="What's in this clip — couple of sentences."
            disabled={saving}
          />
        </label>
        <label className="block">
          <span className="text-xs text-text-muted block mb-0.5">Alt text</span>
          <input
            type="text"
            value={alt}
            onChange={(e) => setAlt(e.target.value)}
            className="w-full bg-bg-input border border-border rounded px-2 py-1 text-sm"
            placeholder="Accessibility / screen-reader text (esp. for images)"
            disabled={saving}
          />
        </label>
        {err ? <div className="text-red text-xs">{err}</div> : null}
        <div className="flex items-center gap-2">
          <button
            type="button"
            onClick={handleSave}
            disabled={saving || !dirty}
            className="px-3 py-1 text-sm bg-accent text-bg rounded hover:opacity-90 disabled:opacity-40"
          >
            {saving ? "Saving…" : "Save"}
          </button>
          <button
            type="button"
            onClick={handleCancel}
            disabled={saving}
            className="px-3 py-1 text-sm border border-border text-text-muted rounded hover:bg-bg-input"
          >
            Cancel
          </button>
        </div>
      </div>
    </section>
  );
}

// ─── Transcripts ───────────────────────────────────────────────────

// TranscriptSection — collapsible transcript view in the drawer.
// Lazy-fetches /media/{id}/transcript on mount because transcripts
// can be large (KB to MB) and most files won't have one open.
//
// Status display:
//   - none yet → "No transcript yet" + "Transcribe" button
//   - pending|running → spinner + "queued / running on Deepgram"
//   - ok → language + text in <details> (first ~250 chars
//     visible by default, expand to see full)
//   - failed → error + "Retry" button (force=true)
//   - skipped → reason + "Re-queue" button (force=true)
function TranscriptSection({
  row,
  apiBase,
  query,
  onTranscribe,
}: {
  row: MediaRow;
  apiBase: string;
  query: string;
  onTranscribe: (force: boolean) => Promise<void>;
}) {
  const [transcript, setTranscript] = useState<Transcript | null>(null);
  const [loading, setLoading] = useState(true);
  const [err, setErr] = useState("");
  const [submitting, setSubmitting] = useState(false);

  const fetchTranscript = useCallback(async () => {
    setLoading(true);
    setErr("");
    try {
      const res = await fetch(`${apiBase}/media/${row.file_id}/transcript?${query}`, {
        credentials: "same-origin",
      });
      if (!res.ok) {
        // 404 / not-found is not an error here — it just means no row.
        setTranscript(null);
        return;
      }
      const data = await res.json();
      if (data.found) {
        setTranscript(data.transcript as Transcript);
      } else {
        setTranscript(null);
      }
    } catch (e) {
      setErr((e as Error).message);
    } finally {
      setLoading(false);
    }
  }, [apiBase, row.file_id, query]);

  useEffect(() => {
    fetchTranscript();
  }, [fetchTranscript]);

  // Re-fetch when status flips to terminal (the parent's
  // media.transcribed event reload doesn't include the text).
  useEffect(() => {
    if (transcript?.status === "pending" || transcript?.status === "running") {
      const id = setInterval(fetchTranscript, 4000);
      return () => clearInterval(id);
    }
  }, [transcript?.status, fetchTranscript]);

  const handleQueue = async (force: boolean) => {
    setSubmitting(true);
    setErr("");
    try {
      await onTranscribe(force);
      // Optimistic — flip our local view to pending so the UI doesn't
      // sit on stale state while the next poll arrives.
      setTranscript({
        file_id: row.file_id,
        status: "pending",
        source_kind: "manual",
      });
    } catch (e) {
      setErr((e as Error).message);
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <section>
      <div className="flex items-center justify-between mb-1">
        <h3 className="text-xs uppercase tracking-wide text-text-dim">Transcript</h3>
        {transcript ? (
          <span className={`inline-flex items-center gap-1 text-xs ${transcriptStatusTextClass(transcript.status)}`}>
            <TranscriptStatusIcon status={transcript.status} className="w-3.5 h-3.5" />
            {transcript.status}
            {transcript.language ? <span className="text-text-dim">· {transcript.language}</span> : null}
          </span>
        ) : null}
      </div>

      {err ? <div className="text-red text-xs mb-1">{err}</div> : null}

      {loading ? (
        <div className="text-xs text-text-dim">Loading…</div>
      ) : !transcript ? (
        <div className="space-y-2">
          <div className="text-xs text-text-dim italic">
            No transcript yet. Queue one to have Deepgram transcribe this file.
          </div>
          <button
            type="button"
            onClick={() => handleQueue(false)}
            disabled={submitting}
            className="px-3 py-1 text-sm bg-accent text-bg rounded hover:opacity-90 disabled:opacity-40"
          >
            {submitting ? "Queueing…" : "Transcribe"}
          </button>
        </div>
      ) : transcript.status === "pending" || transcript.status === "running" ? (
        <div className="text-xs text-text-muted">
          {transcript.status === "pending"
            ? "Queued — the transcriber picks this up on its next sweep."
            : "Running on Deepgram. Refreshing automatically every few seconds."}
        </div>
      ) : transcript.status === "ok" ? (
        <details className="text-sm">
          <summary className="text-text cursor-pointer hover:text-accent">
            {snippet(transcript.text, 200)}
          </summary>
          <div className="mt-2 whitespace-pre-wrap text-text-muted text-sm font-mono leading-relaxed">
            {transcript.text || "(empty)"}
          </div>
          <div className="mt-3 flex items-center gap-2">
            <button
              type="button"
              onClick={() => handleQueue(true)}
              disabled={submitting}
              className="px-3 py-1 text-xs border border-border text-text-muted rounded hover:bg-bg-input"
            >
              {submitting ? "Re-queueing…" : "Re-transcribe"}
            </button>
            {transcript.provider ? (
              <span className="text-xs text-text-dim">
                {transcript.provider}
                {transcript.model ? `:${transcript.model}` : ""}
              </span>
            ) : null}
          </div>
        </details>
      ) : transcript.status === "failed" ? (
        <div className="space-y-2">
          <div className="text-xs text-red whitespace-pre-wrap">
            {transcript.error || "Transcription failed."}
          </div>
          <button
            type="button"
            onClick={() => handleQueue(true)}
            disabled={submitting}
            className="px-3 py-1 text-sm border border-accent text-accent rounded hover:bg-accent hover:text-bg disabled:opacity-40"
          >
            {submitting ? "Retrying…" : "Retry"}
          </button>
        </div>
      ) : transcript.status === "skipped" ? (
        <div className="space-y-2">
          <div className="text-xs text-text-muted">
            Skipped — {transcript.error || "no reason recorded"}.
          </div>
          <button
            type="button"
            onClick={() => handleQueue(true)}
            disabled={submitting}
            className="px-3 py-1 text-sm border border-border text-text rounded hover:bg-bg-input disabled:opacity-40"
          >
            {submitting ? "Queueing…" : "Queue anyway"}
          </button>
        </div>
      ) : null}
    </section>
  );
}

function snippet(text: string | undefined, n: number): string {
  if (!text) return "(empty transcript)";
  const trimmed = text.trim();
  if (trimmed.length <= n) return trimmed;
  return trimmed.slice(0, n).replace(/\s+\S*$/, "") + "…";
}

function transcriptStatusTextClass(status: string): string {
  switch (status) {
    case "ok":
      return "text-text";
    case "pending":
    case "running":
      return "text-accent";
    case "failed":
      return "text-red";
    case "skipped":
      return "text-text-muted";
    default:
      return "text-text-dim";
  }
}

function transcriptBadgeClass(status: string): string {
  // Pill badge in the corner of the tile thumbnail. The colour class
  // also drives the icon stroke via currentColor.
  const base = "inline-flex items-center justify-center rounded-full border bg-bg/80 backdrop-blur p-0.5";
  switch (status) {
    case "ok":
      return `${base} border-accent/40 text-accent`;
    case "pending":
    case "running":
      return `${base} border-border text-accent animate-pulse`;
    case "failed":
      return `${base} border-red/40 text-red`;
    case "skipped":
      return `${base} border-border text-text-muted`;
    default:
      return `${base} border-border text-text-dim`;
  }
}

